import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import Dataset, DataLoader
import requests
from io import BytesIO
import os

class CustomDataset(Dataset):
    def __init__(self, data, labels):
        self.data = data
        self.labels = labels
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]

def download_model_from_url(url):
    response = requests.get(url)
    response.raise_for_status()
    model_data = BytesIO(response.content)
    return torch.load(model_data, map_location=torch.device('cpu'))

def fine_tune_model(model, train_loader, num_epochs=5, learning_rate=0.001):
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    model.to(device)
    
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)
    
    model.train()
    for epoch in range(num_epochs):
        for batch_idx, (data, target) in enumerate(train_loader):
            data, target = data.to(device), target.to(device)
            optimizer.zero_grad()
            output = model(data)
            loss = criterion(output, target)
            loss.backward()
            optimizer.step()
    
    return model

# Example usage
if __name__ == "__main__":
    # Download pretrained model
    model_url = "https://example.com/pretrained_model.pth"
    pretrained_model = download_model_from_url(model_url)
    
    # Prepare custom dataset
    custom_data = torch.randn(1000, 3, 224, 224)
    custom_labels = torch.randint(0, 10, (1000,))
    dataset = CustomDataset(custom_data, custom_labels)
    train_loader = DataLoader(dataset, batch_size=32, shuffle=True)
    
    # Fine-tune model
    fine_tuned_model = fine_tune_model(pretrained_model, train_loader)